from dotenv import load_dotenv

load_dotenv()

API_KEY = os.environ.get("WLT_API_KEY", "YOUR_API_KEY_HERE")
BASE_URL = "https://api.worldlabs.ai/marble/v1"
HEADERS = {
    "Content-Type": "application/json",
    "WLT-Api-Key": API_KEY
}

MODEL = "marble-1.1-plus"

# Master campus panorama — generated by campus_master.py.
# Used as image input to anchor spatial consistency across all scenes.
MASTER_PANO_URL = os.environ.get("MASTER_PANO_URL")

